// src/App.js

import { Routes, Route } from "react-router-dom"; // Import Route and Routes
import LoginPage from "./pages/LoginPage";
import StudentLandingPage from "./pages/StudentLandingPage";
import ProfessorLandingPage from "./pages/ProfessorLandingPage";
import SecretaryLandingPage from "./pages/SecretaryLandingPage";
import AdminLandingPage from "./pages/AdminLandingPage";

function App() {
  return (
    <Routes>
      <Route path="/" element={<LoginPage />} />
      <Route path="/landing/student" element={<StudentLandingPage />} />
      <Route path="/landing/professor" element={<ProfessorLandingPage />} />
      <Route path="/landing/secretary" element={<SecretaryLandingPage />} />
      <Route path="/landing/admin" element={<AdminLandingPage />} />
      {/* Other routes can go here */}
    </Routes>
  );
}

export default App;
